import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const HomePage = () => {
  const [products, setProducts] = useState([]);
  const [user, setUser] = useState(null);
  const [keyword, setKeyword] = useState(''); // Lưu từ khóa tìm kiếm
  const navigate = useNavigate();

  const categories = [
    { id: 1, name: 'Bất động sản', icon: '🏠' },
    { id: 2, name: 'Xe cộ', icon: '🛵' },
    { id: 3, name: 'Đồ điện tử', icon: '📱' },
    { id: 4, name: 'Việc làm', icon: '💼' },
    { id: 5, name: 'Thú cưng', icon: '🐶' },
    { id: 6, name: 'Đồ gia dụng', icon: '🪑' },
  ];

  // Hàm tải sản phẩm (nhận từ khóa và danh mục)
  const fetchProducts = async (searchParam = '', categoryParam = '') => {
    try {
      let url = 'http://localhost:5000/api/products?';
      if (searchParam) url += `keyword=${searchParam}&`;
      if (categoryParam) url += `category=${categoryParam}`;

      const { data } = await axios.get(url);
      setProducts(data);
    } catch (error) { console.error(error); }
  };

  useEffect(() => {
    fetchProducts(); // Tải toàn bộ khi mới vào
    const userInfo = localStorage.getItem('userInfo');
    if (userInfo) setUser(JSON.parse(userInfo));
  }, []);

  // Xử lý Tìm kiếm
  const handleSearch = () => fetchProducts(keyword, '');

  // Xử lý Lọc danh mục
  const handleCategoryClick = (catName) => {
    setKeyword(''); 
    fetchProducts('', catName);
    document.getElementById('product-list').scrollIntoView({ behavior: 'smooth' });
  };

  // Reset về trang chủ
  const handleReset = () => {
    setKeyword('');
    fetchProducts();
    navigate('/');
  };

  const handleLogout = () => {
    localStorage.removeItem('userInfo');
    setUser(null);
    navigate('/login');
  };

  const handleProductClick = (productId) => {
    if (user) navigate(`/product/${productId}`);
    else if (window.confirm("Đăng nhập để xem chi tiết nhé?")) navigate('/login');
  };

  const handleAuthRequired = (actionName) => {
    if (user) {
      if (actionName === 'Đăng tin mới') navigate('/post-product');
    } else {
      if (window.confirm(`Cần đăng nhập để ${actionName}. Đi ngay?`)) navigate('/login');
    }
  };

  return (
    <div className={!user ? 'has-banner' : ''} style={{ paddingBottom: '80px', backgroundColor: '#F4F4F4', minHeight: '100vh' }}>
      
      {/* HEADER */}
      <header className="bg-chotot py-3 sticky-top shadow-sm">
        <div className="container">
          <div className="d-flex justify-content-between align-items-center mb-2">
            <h2 className="fw-bold text-dark m-0" style={{cursor: 'pointer'}} onClick={handleReset}>HaiHand</h2>
            {user ? (
               <div className="d-flex align-items-center gap-2">
                 <span className="fw-bold text-dark" style={{cursor: 'pointer'}} onClick={() => navigate('/profile')}>Hi, {user.name}</span>
                 <button onClick={handleLogout} className="btn btn-sm btn-dark text-warning ms-2">Thoát</button>
               </div>
            ) : (
               <span className="fw-bold" onClick={() => navigate('/login')} style={{cursor:'pointer'}}>Đăng nhập</span>
            )}
          </div>
          
          {/* Ô TÌM KIẾM */}
          <div className="input-group">
            <input 
              type="text" className="form-control border-0" 
              placeholder="Tìm kiếm (ví dụ: iphone, xe...)" 
              value={keyword}
              onChange={(e) => setKeyword(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSearch()} 
            />
            <button className="btn btn-dark text-warning" onClick={handleSearch}>🔍</button>
          </div>
        </div>
      </header>

      <div className="container mt-3">
        {/* DANH MỤC */}
        <div className="bg-white p-3 rounded shadow-sm mb-3">
            <h6 className="fw-bold mb-3">Khám phá danh mục</h6>
            <div className="d-flex justify-content-between text-center overflow-auto">
                {categories.map(cat => (
                    <div key={cat.id} className="category-item px-2" onClick={() => handleCategoryClick(cat.name)}>
                        <div className="category-icon">{cat.icon}</div>
                        <small style={{fontSize: '12px'}}>{cat.name}</small>
                    </div>
                ))}
            </div>
        </div>

        {/* DANH SÁCH SẢN PHẨM */}
        <div id="product-list" className="bg-white p-3 rounded shadow-sm">
          <h6 className="fw-bold mb-3">Tin đăng dành cho bạn</h6>
          
          {products.length === 0 && (
             <div className="text-center py-5 text-muted">
                <p style={{fontSize: '50px'}}>🙈</p>
                <p>Không tìm thấy sản phẩm nào!</p>
                <button className="btn btn-sm btn-outline-primary" onClick={handleReset}>Xem tất cả</button>
             </div>
          )}

          <div className="row">
            {products.map((product) => (
              <div className="col-6 col-md-3 mb-3" key={product._id} 
                   onClick={() => handleProductClick(product._id)}
                   style={{cursor: 'pointer'}}>
                <div className="card h-100 border-0 shadow-sm animate__animated animate__fadeIn">
                  <img src={product.image} className="card-img-top rounded" alt={product.name} style={{height: '150px', objectFit: 'cover'}} />
                  <div className="card-body p-2">
                    <h6 className="card-title text-truncate mb-1">{product.name}</h6>
                    <p className="card-text text-danger fw-bold mb-0">
                      {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.price)}
                    </p>
                    <small className="text-muted" style={{fontSize: '10px'}}>{product.location}</small>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {!user && (
        <div className="sticky-banner d-flex justify-content-between align-items-center animate__animated animate__slideInUp">
            <div><p className="mb-0 fw-bold">Đăng nhập để không bỏ lỡ!</p></div>
            <button onClick={() => navigate('/login')} className="btn btn-chotot px-4">Đăng nhập</button>
        </div>
      )}
      <button className="fab-btn" onClick={() => handleAuthRequired('Đăng tin mới')}><span className="fab-icon">+</span></button>

    </div>
  );
};

export default HomePage;
